var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……하. 하하.","JPN":"……は、はは。","ENG":"...Ha. Haha.","TWN":"……哈。哈哈。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이거 전부 거짓말이죠? 이럴 리가 없잖아요……?","JPN":"これって、全部嘘でしょう？　そんなわけないじゃないですか……？","ENG":"This is all a lie, right? This can't be...","TWN":"這全都是騙人的吧？怎麼可能會這樣……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오랜만에 본 가족인데, 낮에 버릇없이 큰소리친 거 아직 사과도 못 드렸는데…….","JPN":"久しぶりに家族に会ったのに、昼間に文句言ったこともまだ謝ってないのに……","ENG":"I haven't seen my family in so long, and I didn't have a chance to apologize for shouting at them earlier...","TWN":"好久不見的家人，還沒來得及因為白天的衝動而道歉……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래, 전부 꿈일 거예요. 이런 건 현실이 아니야……!","JPN":"そう、これは全部夢ですよね。こんなの、現実なんかじゃない……！","ENG":"Yeah, this must all be a dream. This isn't real...!","TWN":"對，這一切都是夢。這不是真實的……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니요. 이건 틀림없는 현실이랍니다,","JPN":"いいえ。これは間違いなく現実です。","ENG":"No. This is definitely real.","TWN":"不，這就是無可辯駁的現實。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 눈을 돌리지 마세요. 지금부터 일어나는 모든 현상을 똑똑히 마주하는 겁니다.","JPN":"ですから、目をそらさないでください。これから起こるすべての現象をとくと見るのです。","ENG":"So, don't look away. You will have to witness every phenomenon that is about to happen here now.","TWN":"所以不要轉移視線。從現在開始，清楚地面對在你身上發生的一切吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"현상이라고오……?","JPN":"現象……？","ENG":"Phenomenon...?","TWN":"發生的……一切嗎……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NOELPAPA_SWANSONG_NPC_NULL","text":{"KOREA":"노엘? 여기서 뭐하는 거니……?","JPN":"ノエル？　ここで何をやってるんだ……？","ENG":"Noelle? What are you doing here...?","TWN":"洛艾兒？你在這裡做什麼……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아빠……? 아빠는 분명히……?","JPN":"お父さん……？　お父さんは確か……？","ENG":"Dad...? That was Dad...","TWN":"爸爸……？爸爸明明已經……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아하! 역시 꿈이었구나!","JPN":"ほら！　やっぱり夢だったんだ！","ENG":"Aha! So this is a dream!","TWN":"哈哈！果然是夢啊！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 무의식이 그의 죽음을 받아드리는 걸 거부한 탓입니다.","JPN":"あなたの無意識が彼の死を受け入れることを拒んでいるからです。","ENG":"That is because your subconsciousness is refusing to accept his death.","TWN":"因為你在潛意識裡拒絕接受他的死亡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 그가 죽지 않게끔, 현실이 개변된 거죠.","JPN":"なので、彼が死なないように現実が書きかえられたのです。","ENG":"You are altering the reality to prevent him from dying.","TWN":"所以為了不讓他死去，現實被改變了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"현실을 개변한다고요? 대체 무슨 말이죠?","JPN":"現実を書きかえる？　よ、よくわかりません。どういうことですか？","ENG":"Altering reality? What do you mean?","TWN":"現實被改變了？這到底是什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NOELPAPA_SWANSONG_NPC_NULL","text":{"KOREA":"노엘! 여기 있으면 안 돼! 어서 도망치렴! 아빠가……!","JPN":"ノエル！　ここにいてはダメだ！　早く逃げろ！　お父さんが……！","ENG":"Noelle! You can't be here! Run! I'll–!","TWN":"洛艾兒！這裡不安全！快逃！爸爸會……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 이런 뜻이랍니다, 노엘.","JPN":"それはこういう意味ですよ、ノエル。","ENG":"This is what I meant, Noelle.","TWN":"是這個意思，洛艾兒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어, 어어……!?","JPN":"え、ええ……！？","ENG":"W-what...?!","TWN":"啊？啊啊……！?"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 안돼! 하지마요! 하지마아아아아아아아……!!","JPN":"だ、ダメ！　やめて！　やめてえええええええ……！！","ENG":"N-no! Stop it! STOOOOOP...!!","TWN":"不、不行！不要這樣！不要啊啊啊啊啊啊啊……！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 아빠……!? ","JPN":"お、お父さん……！？ ","ENG":"D-Dad...?!","TWN":"啊，爸爸……！？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이럴 리 없어……! 왜 대체 왜……!?","JPN":"こんなはずない……！　いったいどうして……！？","ENG":"This isn't happening...! Why...?!","TWN":"這不可能……！為什麼，為什麼……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NOELPAPA_SWANSONG_NPC_NULL","text":{"KOREA":"노엘? 여기서 뭐하는 거니……?","JPN":"ノエル？　ここで何をやってるんだ……？","ENG":"Noelle? What are you doing here...?","TWN":"洛艾兒？你在這裡做什麼……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 아… 빠……?","JPN":"お、お父……さん……？","ENG":"D-Da... d...?","TWN":"啊，啊……爸爸！快，快……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NOELPAPA_SWANSONG_NPC_NULL","text":{"KOREA":"주저하고 있을 시간이 없어. 여기 있으면 안 돼. 어서……!","JPN":"時間がない。ここにいてはダメだ。早く……！","ENG":"There's no time to waste. You can't be here. Go...!","TWN":"沒時間猶豫了。你不能待在這裡！快點……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그만, 그만해…….","JPN":"もう、やめて……","ENG":"Stop it. Enough...","TWN":"夠了，夠了……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제발… 이제 그만……! 더는 보고 싶지 않아아아아……!","JPN":"お願い……もうやめてよ……！　もう見たくない……！","ENG":"Please... Just stop it...! I don't want to see any more...!","TWN":"拜託了……到此為止吧……！我再也不想看到了啊啊啊……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……이제 끝난 건가?","JPN":"……終わったの？","ENG":"...Is it over now?","TWN":"……現、現在結束了嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"흐, 흐흑… 대체 왜……? 대체 왜 이런 짓을……?","JPN":"う、ううっ……いったいどうして……？　どうしてこんなことを……？","ENG":"*Sniffle* Just why...? Why are you doing this to me...?","TWN":"嗚，嗚嗚……到底為什麼……？到底為什麼要做這種事……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이제 이걸로 만족해요……?","JPN":"もうこれで満足ですか……？","ENG":"Are you satisfied now...?","TWN":"現在這樣你滿意了嗎……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"스완……?","JPN":"スワン……？","ENG":"Swan...?","TWN":"史旺……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"노엘 라이트.","JPN":"ノエル・ライト。","ENG":"Noelle Wright.","TWN":"洛艾兒·萊特。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 바로 이곳에서 시작된 겁니다.","JPN":"すべてはここから始まりました。","ENG":"It all started here.","TWN":"一切都從這裡開始。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"시작? 뭐가 시작됐다는 거예요……?","JPN":"始まる？　何が始まったってことですか……？","ENG":"Started? What started...?","TWN":"開始？什麼開始……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신 말은 하나도 알아들을 수가 없다고요……!","JPN":"あなたの言ってること、さっきから全然わからないよ……！","ENG":"I don't understand a word you're saying...!","TWN":"我完全聽不懂你在說什麼……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 무대에서 당신이 맡은 역할은 <color=#ffd34c>광대</color>.","JPN":"この舞台であなたが担当する役は<color=#ffd34c>クラウン</color>。","ENG":"The role for you in this performance is the <color=#ffd34c>clown</color>.","TWN":"在這個舞台上，你扮演的角色是<color=#ffd34c>小丑</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임이 끝나고, 모든 천체가 제 위치를 찾은 순간.","JPN":"クリフォトゲームが終わり、すべての天体があるべき場所に戻った瞬間、","ENG":"After the Qliphoth Game ends, and all celestial bodies find their place.","TWN":"逆卡巴拉遊戲結束後，所有天體都回到了各自的位置。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"달의 세피라가 이 땅을 비추면서 당신의 모든 여정이 시작되었으니까요.","JPN":"月のセフィラがこの地を照らし、あなたの旅は始まったのです。","ENG":"Your journey started when the moon's Sephira illuminated this land.","TWN":"當月之塞菲拉照耀這片土地時，你的旅程便開始了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"광대인 당신은 여정에서 많은 인연들을 만나게 되었죠.","JPN":"クラウンであるあなたは、旅の途中で様々な人に出会いました。","ENG":"You, the clown, met many people in your journey.","TWN":"作為冒險者的你，在旅途中遇到了許多緣分。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 중에는 소중한 인연도 있었고, 맞서 싸워야만 하는 적도 있었어요.","JPN":"その中には大事な仲間や、立ち向かうべき敵もいました。","ENG":"There were cherished relationships as well as enemies you had to encounter.","TWN":"其中有珍貴的緣分，也有必須對抗的敵人。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 크고 작은 승리를 거치며, 그로부터 많은 것들을 배울 수 있었습니다.","JPN":"やがて、あなたは大小の勝利を経て、たくさんのことを学びました。","ENG":"All your victories, big and small, have added up to teach you many things.","TWN":"你通過大大小小勝利，從中學到了很多東西。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"한 차례의 여정이 끝난 뒤, 한 사람으로서 자격을 갖춘 당신은 비로소 이곳으로 돌아왔죠.","JPN":"旅が一段落し、一人前の資格を備えたあなたは、やっとここに帰ってきたのです。","ENG":"After a journey is complete, you finally return here. As a qualified person.","TWN":"這段旅程結束後，作為一個合格的“人”，你終於回到了這裡。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자신이 만들어낸 <color=#ffd34c>작은 세계</color>에.","JPN":"あなた自身が作り出した<color=#ffd34c>小さな世界</color>へ。","ENG":"To this <color=#ffd34c>little world</color> you made for yourself.","TWN":"回到了自己創造的<color=#ffd34c>小世界</color>。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제가 만들어낸 세계라고요……?","JPN":"私が作り出した世界……？","ENG":"A world that I made...?","TWN":"這是我創造的世界……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 명단을 읽어보세요.","JPN":"このリストを読んでみてください。","ENG":"Read the list.","TWN":"請看這份名單。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……전부 이 마을 사람들이잖아요. 이게 뭐 어쨌다는 거죠?","JPN":"……全員この村の人たち……これがどうしたっていうんですか。","ENG":"...It has all the names of the villagers. What about it?","TWN":"……全是這個村子的村民啊。這到底是什麼意思？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마을 사람들? 틀렸어요, 노엘.","JPN":"村の人たち？　違います、ノエル。","ENG":"Villagers? You are wrong, Noelle.","TWN":"村民們？錯了，洛艾兒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 어떠한 경로로 손에 넣은 대정화 전쟁의 민간인 사상자 리스트를 간추린 겁니다.","JPN":"それはとある経路で手に入れた大浄化戦争の民間死傷者をまとめたリストです。","ENG":"This list is a summary of the civilian casualties from the Grand Purification War that I obtained through certain means.","TWN":"這是我通過某種途徑獲得的大淨化戰爭中平民傷亡名單的摘要。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"민간인 사상자 리스트……?","JPN":"民間死傷者のリスト……？","ENG":"A list of civilian causalities...?","TWN":"平民傷亡名單……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"20년 전, 이 마을은 전쟁에 휘말려 마을 주민은 전원 사망했거든요.","JPN":"20年前、この村は戦争に巻き込まれ、村の住民は全員死亡しているのです。","ENG":"Twenty years ago, all the villagers here died after being caught up in the war.","TWN":"20年前，這個村莊捲入了戰爭，所有村民都死亡了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"마을 사람들이 20년 전에 전원 사망……?","JPN":"村の人たちが20年前に全員死亡……？","ENG":"Everyone here died twenty years ago...?","TWN":"大家在20年前全部都已經死了……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리를 하는 거예요! 이곳 사람들을 죽인 건 당신이잖아……!!","JPN":"ふざけないで！　みんなを殺したのはあなたじゃない……！！","ENG":"What are you talking about?! You killed all of them...!!","TWN":"你在說什麼！是你殺了這裡的所有人……！！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요.","JPN":"言ったはずです。","ENG":"I told you.","TWN":"我應該已經告訴過你了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 당신이 만들어낸 작은 세계라고.","JPN":"ここはあなたが作り出した小さな世界だと。","ENG":"You created this little world.","TWN":"這裡是你創造的小世界。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대정화 전쟁 이후, 이곳은 지도에서조차 지워진 침식지대에 불과했어요.","JPN":"大浄化戦争以後、ここは地図でさえ消されてしまった侵食地帯に過ぎませんでした。","ENG":"After the Grand Purification War, this place was a Corrupted Area that was even erased from the maps.","TWN":"大淨化戰爭之後，這裡不過是從地圖上被抹去的侵蝕地帶。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 왜 이 마을은 다른 거주 구역과 이렇게 동떨어진 곳에 위치하고 있을까요?","JPN":"そもそも、どうしてこの村は他の居住区域とこんなにも離れた場所にあるのでしょうか。","ENG":"Why do you think this village is located so far out from the other residential areas in the first place?","TWN":"那這個村莊為什麼會與其他居住區如此隔絕呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"교통이 불편하니, 당연히 유통도 불편하겠죠.","JPN":"交通が不便で、当然流通にも困っていたのでしょう。","ENG":"With no transport infrastructure, logistics is naturally inconvenient.","TWN":"交通不便，流通自然也不便。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로 이 마을은 그런 불편을 감수하고 많은 걸 마을 내부에서 해결하고 있어요.","JPN":"結果的にこの村はそのような不便を受け入れ、ほとんどのことを村の内部で解決していました。","ENG":"As a result, this village had endured these inconveniences and solved many of its problems internally.","TWN":"結果，這個村子卻忍受著這些不便，自給自足了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 이런 불편에도 왜 마을 사람들은 위화감을 느끼지 못할까요?","JPN":"でも、こんな不便にも関わらず村の人たちはどうして違和感を感じていなかったのでしょうか。","ENG":"But why did the villagers not feel any discomfort?","TWN":"但是，為什麼村民們在這種情況下，卻沒有任何違和感呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그건……?","JPN":"そ、それは……？","ENG":"Th-that's...","TWN":"那、那個……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이유는 간단해요. 노엘.","JPN":"理由は簡単です。ノエル。","ENG":"The reason is simple, Noelle.","TWN":"理由很簡單，洛艾兒。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 위화감을 느끼지 못하니까.","JPN":"あなたが違和感を感じていないから。","ENG":"It's because you didn't feel any discomfort.","TWN":"因為你沒有感到任何違和感。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 부모, 이 마을의 이웃, 마을의 환경과 지리, 역사와 정보…….","JPN":"あなたの両親、この村の隣人、村の環境と地理、歴史と情報……","ENG":"Your parents, neighbors, the village's geolocation and environment, its history and information...","TWN":"你的父母，這個村莊的鄰居，村莊的環境和地理，歷史和資訊……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 마을을 구성하는 모든 것은 당신에 의해 덮어 씌워진 허구에 불과하답니다.","JPN":"この村を構成するすべてのものはあなたによって上書きされた虚構に過ぎません。","ENG":"It was all a fiction of your imagination that you covered up.","TWN":"這個村莊的一切都是你編造的虛構之物。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 아아……. 아니야……!","JPN":"あ、ああ……違う……！","ENG":"N.... NO...!","TWN":"啊，啊啊……，不，不是……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아요……! 내가 어떻게……?","JPN":"そんなはずないでしょう……？　私がどうやって……？","ENG":"That's impossible...! How could I...?","TWN":"這怎麼可能……！我怎麼會……？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 노엘 라이트라는 <color=#ffd34c>껍데기</color>조차도 예외가 아니에요.","JPN":"そのノエル・ライトという<color=#ffd34c>殻</color>も例外ではありません。","ENG":"The <color=#ffd34c>shell</color> you call Noelle Wright is no exception either.","TWN":"就連那個叫洛艾兒·萊特的<color=#ffd34c>軀殼</color>也不例外。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"원래라면 20년 전 전쟁에 휘말려 죽은, 도시를 동경하는 시골 소녀에 불과했겠죠.","JPN":"本来なら20年前の戦争に巻き込まれて死んだ、都市に憧れる田舎少女に過ぎなかったはずです。","ENG":"Originally, she was just a country girl who admired the city and died in the war twenty years ago.","TWN":"本來她只是一個嚮往城市的鄉村少女，20年前就應該在戰爭中喪生了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"파노라마의 세계에서 당신의 거울상과 마주한 적이 있을 거예요.","JPN":"あなたはパノラマの世界で、自分の鏡像と向き合いました。","ENG":"I'm sure you met your reflection in Panorama's world.","TWN":"在全景世界中，你可能曾與自己的鏡像相遇。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그때 파노라마는 당신의 본질이 무엇인지 정확하게 규정하지 못했어요.","JPN":"あの時、パノラマはあなたの本質がどんなものなのか、はっきりと定めることに失敗しました。","ENG":"Even then, Panorama couldn't accurately define your essence.","TWN":"那時，全景並未準確定義出你的本質。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 결과, 당신의 본질이 아닌 껍데기만을 비추었죠.","JPN":"その結果、あなたの本質ではなく殻だけを映した。","ENG":"Thus, it reflected the shell and not your essence.","TWN":"結果，它只映出了你的外殼，而非本質。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……그, 그럴리가.","JPN":"……そ、そんな。","ENG":"...Th-that can't be.","TWN":"……沒，沒有。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"노, 놀리는 거 아니지? 말했잖아. 이건 내가 정말 있는 게 아니라, 갖고 싶은 거라구.","JPN":"か、からかっているの？　言ったでしょう。これは本当にあるものではなくて、私が欲しいものだって。","ENG":"Y-you're not teasing me, right? I told you. These are not things that I really have, but things I want.","TWN":"你、你是在測試我嗎？我說過了，這些都是我想要的，而不是已經擁有的。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"치즈도… 엄마 아빠도… 이런 넓은 과일숲도…","JPN":"チーズも……お母さんも、お父さんも……こんな広い果樹園も……","ENG":"Cheese... Mom and Dad... and even the vast orchard...","TWN":"起司……爸爸媽媽……還有這個大果林……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_MIRROR","text":{"KOREA":"나한텐… 아무것도 없단 말이야.","JPN":"私には……何もないんだ。","ENG":"You see... I have none of those.","TWN":"我……什麼都沒有。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신… 정체가 뭐죠?","JPN":"あなた……何者ですか？","ENG":"Who... are you?","TWN":"你……你到底是誰？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_MIRROR","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면 당신의 본질은 무엇일까요?","JPN":"それなら、あなたの本質とは何でしょう？","ENG":"Then what is your essence?","TWN":"那麼，你的本質是什麼呢？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 아주 오랫동안 당신의 본질을 좇아왔습니다.","JPN":"私はとても長い間、あなたの本質を追い続けてきました。","ENG":"I have long chased after it.","TWN":"一直以來，我都在追尋你的本質。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 그 본질은 인간이 아닌, 어떠한 <color=#ffd34c>신적 존재</color>.","JPN":"おそらくその本質は人間ではなく、とある<color=#ffd34c>神的存在</color>。","ENG":"Perhaps your essence is not human, and some <color=#ffd34c>divine being</color>.","TWN":"也許你的本質並非人類，而是某種<color=#ffd34c>神性存在</color>。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"감히 추정컨대, 그건 세계를 만드는 법칙인 <color=#ffd34c>세피로트 나무</color>의 일부…….","JPN":"予想するに、それは世界を作る法則である<color=#ffd34c>セフィロト</color>の一部……","ENG":"I dare to guess that it is a part of the law of creating a world, the <color=#ffd34c>Tree of Sephiroth</color>...","TWN":"我大膽推測，那是構建世界法則的<color=#ffd34c>生命樹</color>的一部分……"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 땅에 강림한 <color=#ffd34c>세피라</color>의 화신이 아닐까 추측하고 있어요.","JPN":"この地に降臨した<color=#ffd34c>セフィラ</color>の化身ではないかと思っています。","ENG":"I assume that you are the personification of <color=#ffd34c>Sephira</color> who descended on this land.","TWN":"我猜測你便是降臨此地的<color=#ffd34c>塞菲拉</color>的化身。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비유적인 표현을 빌리자면…….","JPN":"例えるなら……","ENG":"In a way...","TWN":"借用比喻的說法……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 당신이야말로, <color=#ffd34c>천사</color>라고 할 수 있을지도 모르겠네요.","JPN":"そうですね。あなたこそ、<color=#ffd34c>天使</color>と言えるのかもしれません。","ENG":"Yes. You might be an <color=#ffd34c>angel</color>.","TWN":"沒錯。或許你才是那個<color=#ffd34c>天使</color>。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……천사?","JPN":"……天使？","ENG":"...An angel?","TWN":"……天使？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 아주 오래전부터 이 순간만을 준비해왔답니다.","JPN":"私はとても長い間、このシーンを設計してきました。","ENG":"I have prepared for this moment for a very long time.","TWN":"我從很久以前就開始為這一刻做準備了。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"너무 이르지도, 늦지도 않은 타이밍에 당신이 스스로의 힘을 자각하게끔 말이죠.","JPN":"早くも、遅くもない、ちょうどいいタイミングにあなたが自分の力を自覚するように。","ENG":"In order to make sure you become aware of your powers at a time that is not too late nor early.","TWN":"在不早不晚的時機，讓你意識到自己的力量。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 저에게는 당신의 힘이 필요하답니다. 노엘 라이트.","JPN":"そして、私にはあなたの力が必要なんです、ノエル・ライト。","ENG":"And I need your strength, Noelle Wright.","TWN":"而且我需要你的力量，洛艾兒·萊特。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신이 하는 말…….","JPN":"あなたの話……","ENG":"What you just said...","TWN":"你說的話……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소리인지 하나도 모르겠어요…….","JPN":"何を言ってるのかさっぱりわかりません……","ENG":"I don't understand a word of it...","TWN":"我好像完全聽不懂……"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이런 짓을 저질러 놓고……. 제 힘이 필요하다고요……?","JPN":"こんなことをしておいて……私の力が必要だって……？","ENG":"After doing all this... you're asking me to help you...?","TWN":"而且做了這種事……還說需要我的力量……？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 제가 순순히 당신 말을 따를 것 같나요……?","JPN":"私が素直にあなたの言うとおりするって、本当に思っているんですか？","ENG":"Then, did you think I'd just say yes...?","TWN":"你覺得我會乖乖聽你的嗎……？"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_02"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 그렇다면 저는 당신에게 절망을 선사할 수밖에 없겠군요.","JPN":"さあ。それでしたら私は、あなたに絶望をプレゼントするしかありませんね。","ENG":"Well. If you do not comply, I'll have no choice but to bring you despair.","TWN":"那麼，如果你拒絕，我便只能給你帶來絕望了。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 작은 세계를 부수고, 진실과 마주하게끔.","JPN":"この小さな世界を壊し、真実と向き合えるように。","ENG":"I will destroy this little world of yours and force you to face the truth.","TWN":"打破這個小小的世界，讓你直面那個真相。"},"stage":{"bg":"CHURCH","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};